// 结存归零
resetSelectedBalance() {
    const selection = this.tableData.multipleSelectionData.selection;
    if (selection.length === 0) {
        this.$message.warning('请先选择要结存归零的记录');
        return;
    }
    this.$confirm(`确定要将选中的 ${selection.length} 条记录的结存归零吗？此操作会将收入和支出同时置为0。`, '确认', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
    }).then(() => {
        const promises = selection.map(row => {
            const detail = {
                id: row.id,
                date: row.date,
                project: {id: row.project ? row.project.id : null},
                account: {id: row.account ? row.account.id : null},
                department: {id: row.department ? row.department.id : null},
                category: {id: row.category ? row.category.id : null},
                earning: 0,
                expense: 0,
                balance: 0,
                digest: row.digest || '无'
            };
            return this.$api.detailApi.update(detail);
        });
        this.tableData.loading = true;
        Promise.all(promises).then(() => {
            this.$message.success('结存归零成功');
            this.loadData();
        }).catch(err => {
            this.$message.error('结存归零失败：' + (err.message || '未知错误'));
            this.tableData.loading = false;
        });
    }).catch(() => {});
},
